B.PY=new A.an("Your Warrior awakens \u2014 set a bold boundary or take a courageous step today.","\u0422\u0432\u043e\u0439 \u0412\u043e\u0438\u043d \u043f\u0440\u043e\u0441\u044b\u043f\u0430\u0435\u0442\u0441\u044f \u2014 \u0443\u0441\u0442\u0430\u043d\u043e\u0432\u0438 \u0441\u043c\u0435\u043b\u0443\u044e \u0433\u0440\u0430\u043d\u0438\u0446\u0443 \u0438\u043b\u0438 \u0441\u0434\u0435\u043b\u0430\u0439 \u043c\u0443\u0436\u0435\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0439 \u0448\u0430\u0433.","archetype_warrior",null)
B.Pl=new A.an("The Magician in you sees clearly \u2014 use your insight to solve what others can't.","\u041c\u0430\u0433 \u0432 \u0442\u0435\u0431\u0435 \u0432\u0438\u0434\u0438\u0442 \u044f\u0441\u043d\u043e \u2014 \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0439 \u043f\u0440\u043e\u043d\u0438\u0446\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c, \u0447\u0442\u043e\u0431\u044b \u0440\u0435\u0448\u0438\u0442\u044c \u0442\u043e, \u0447\u0442\u043e \u0434\u0440\u0443\u0433\u0438\u043c \u043d\u0435 \u043f\u043e\u0434 \u0441\u0438\u043b\u0443.","archetype_magician",null)
B.Pj=new A.an("Magician energy peaks \u2014 study, learn, or teach something profound today.","\u042d\u043d\u0435\u0440\u0433\u0438\u044f \u041c\u0430\u0433\u0430 \u043d\u0430 \u043f\u0438\u043a\u0435 \u2014 \u0438\u0437\u0443\u0447\u0438, \u0443\u0437\u043d\u0430\u0439 \u0438\u043b\u0438 \u043d\u0430\u0443\u0447\u0438 \u0447\u0435\u043c\u0443-\u0442\u043e \u0433\u043b\u0443\u0431\u043e\u043a\u043e\u043c\u0443 \u0441\u0435\u0433\u043e\u0434\u043d\u044f.","archetype_magician",null)
B.P2=new A.an("The Lover archetype guides you \u2014 connect deeply, create beauty, open your heart.","\u0410\u0440\u0445\u0435\u0442\u0438\u043f \u041b\u044e\u0431\u044f\u0449\u0435\u0433\u043e \u0432\u0435\u0434\u0451\u0442 \u0442\u0435\u0431\u044f \u2014 \u0441\u043e\u0435\u0434\u0438\u043d\u044f\u0439\u0441\u044f \u0433\u043b\u0443\u0431\u043e\u043a\u043e, \u0441\u043e\u0437\u0434\u0430\u0432\u0430\u0439 \u043a\u0440\u0430\u0441\u043e\u0442\u0443, \u043e\u0442\u043a\u0440\u043e\u0439 \u0441\u0435\u0440\u0434\u0446\u0435.","archetype_lover",null)
B.OY=new A.an("Lover energy flows \u2014 nurture one relationship or creative project with full presence.","\u042d\u043d\u0435\u0440\u0433\u0438\u044f \u041b\u044e\u0431\u044f\u0449\u0435\u0433\u043e \u0442\u0435\u0447\u0451\u0442 \u2014 \u043f\u043e\u0434\u043f\u0438\u0442\u0430\u0439 \u043e\u0434\u043d\u043e \u043e\u0442\u043d\u043e\u0448\u0435\u043d\u0438\u0435 \u0438\u043b\u0438 \u043f\u0440\u043e\u0435\u043a\u0442 \u0441 \u043f\u043e\u043b\u043d\u044b\u043c \u043f\u0440\u0438\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0435\u043c.","archetype_lover",null)
B.OV=new A.an("Meditate on the code associated with your weakest sephira for 3 minutes.","\u041c\u0435\u0434\u0438\u0442\u0438\u0440\u0443\u0439 \u043d\u0430 \u043a\u043e\u0434, \u0441\u0432\u044f\u0437\u0430\u043d\u043d\u044b\u0439 \u0441 \u0442\u0432\u043e\u0435\u0439 \u0441\u043b\u0430\u0431\u0435\u0439\u0448\u0435\u0439 \u0441\u0435\u0444\u0438\u0440\u043e\u0439, 3 \u043c\u0438\u043d\u0443\u0442\u044b.","general",null)
B.Pe=new A.an("Review the Tree of Life. Where does energy flow freely and where is it blocked?","\u0420\u0430\u0441\u0441\u043c\u043e\u0442\u0440\u0438 \u0414\u0440\u0435\u0432\u043e \u0416\u0438\u0437\u043d\u0438. \u0413\u0434\u0435 \u044d\u043d\u0435\u0440\u0433\u0438\u044f \u0442\u0435\u0447\u0451\u0442 \u0441\u0432\u043e\u0431\u043e\u0434\u043d\u043e, \u0430 \u0433\u0434\u0435 \u0437\u0430\u0431\u043b\u043e\u043a\u0438\u0440\u043e\u0432\u0430\u043d\u0430?","general",null)
B.Pc=new A.an("Choose one 72 Name code intuitively and carry its vibration through the day.","\u0412\u044b\u0431\u0435\u0440\u0438 \u043e\u0434\u0438\u043d \u043a\u043e\u0434 72 \u0418\u043c\u0451\u043d \u0438\u043d\u0442\u0443\u0438\u0442\u0438\u0432\u043d\u043e \u0438 \u043d\u0435\u0441\u0438 \u0435\u0433\u043e \u0432\u0438\u0431\u0440\u0430\u0446\u0438\u044e \u0447\u0435\u0440\u0435\u0437 \u0432\u0435\u0441\u044c \u0434\u0435\u043d\u044c.","general",null)
B.PI=new A.an("Balance action and rest. The middle pillar teaches equanimity.","\u0411\u0430\u043b\u0430\u043d\u0441\u0438\u0440\u0443\u0439 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435 \u0438 \u043e\u0442\u0434\u044b\u0445. \u0421\u0440\u0435\u0434\u043d\u0438\u0439 \u0441\u0442\u043e\u043b\u043f \u0443\u0447\u0438\u0442 \u043d\u0435\u0432\u043e\u0437\u043c\u0443\u0442\u0438\u043c\u043e\u0441\u0442\u0438.","general",null)
B.PW=new A.an('Practice the "as above, so below" principle. Align your inner state with your outer actions.','\u041f\u0440\u0430\u043a\u0442\u0438\u043a\u0443\u0439 \u043f\u0440\u0438\u043d\u0446\u0438\u043f "\u043a\u0430\u043a \u0432\u0432\u0435\u0440\u0445\u0443, \u0442\u0430\u043a \u0438 \u0432\u043d\u0438\u0437\u0443". \u0421\u043e\u0433\u043b\u0430\u0441\u0443\u0439 \u0432\u043d\u0443\u0442\u0440\u0435\u043d\u043d\u0435\u0435 \u0441\u043e\u0441\u0442\u043e\u044f\u043d\u0438\u0435 \u0441 \u0432\u043d\u0435\u0448\u043d\u0438\u043c\u0438 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044f\u043c\u0438.',"general",null)
B.PG=new A.an("Contemplate one sephira deeply today. What does it teach about your current challenge?","\u0421\u043e\u0437\u0435\u0440\u0446\u0430\u0439 \u043e\u0434\u043d\u0443 \u0441\u0435\u0444\u0438\u0440\u0443 \u0433\u043b\u0443\u0431\u043e\u043a\u043e \u0441\u0435\u0433\u043e\u0434\u043d\u044f. \u0427\u0435\u043c\u0443 \u043e\u043d\u0430 \u0443\u0447\u0438\u0442 \u043e \u0442\u0432\u043e\u0451\u043c \u0442\u0435\u043a\u0443\u0449\u0435\u043c \u0432\u044b\u0437\u043e\u0432\u0435?","general",null)
B.Pf=new A.an("Notice the interplay of giving (Chesed) and receiving (Gevurah) in your day.","\u0417\u0430\u043c\u0435\u0447\u0430\u0439 \u0432\u0437\u0430\u0438\u043c\u043e\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435 \u043e\u0442\u0434\u0430\u0447\u0438 (\u0425\u0435\u0441\u0435\u0434) \u0438 \u043f\u043e\u043b\u0443\u0447\u0435\u043d\u0438\u044f (\u0413\u0432\u0443\u0440\u0430) \u0432 \u0441\u0432\u043e\u0451\u043c \u0434\u043d\u0435.","general",null)
B.PN=new A.an("The 4 Pillars of the Sphinx remind us: Know, Dare, Will, and be Silent. Which do you need most?","4 \u0421\u0442\u043e\u043b\u043f\u0430 \u0421\u0444\u0438\u043d\u043a\u0441\u0430 \u043d\u0430\u043f\u043e\u043c\u0438\u043d\u0430\u044e\u0442: \u0417\u043d\u0430\u0442\u044c, \u0414\u0435\u0440\u0437\u0430\u0442\u044c, \u0416\u0435\u043b\u0430\u0442\u044c \u0438 \u041c\u043e\u043b\u0447\u0430\u0442\u044c. \u0427\u0442\u043e \u0442\u0435\u0431\u0435 \u043d\u0443\u0436\u043d\u0435\u0435 \u0432\u0441\u0435\u0433\u043e?","general",null)
B.Pu=new A.an("Today is ruled by Chesed \u2014 practice generosity and unconditional giving.","\u0421\u0435\u0433\u043e\u0434\u043d\u044f \u043f\u0440\u0430\u0432\u0438\u0442 \u0425\u0435\u0441\u0435\u0434 \u2014 \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u0443\u0439 \u0449\u0435\u0434\u0440\u043e\u0441\u0442\u044c \u0438 \u0431\u0435\u0437\u0443\u0441\u043b\u043e\u0432\u043d\u0443\u044e \u043e\u0442\u0434\u0430\u0447\u0443.","cosmic_weekday_5",null)
B.PB=new A.an("Gevurah governs today. Set a firm boundary and honor it with strength.","\u0421\u0435\u0433\u043e\u0434\u043d\u044f \u043f\u0440\u0430\u0432\u0438\u0442 \u0413\u0432\u0443\u0440\u0430. \u0423\u0441\u0442\u0430\u043d\u043e\u0432\u0438 \u0442\u0432\u0451\u0440\u0434\u0443\u044e \u0433\u0440\u0430\u043d\u0438\u0446\u0443 \u0438 \u0447\u0442\u0438 \u0435\u0451 \u0441 \u0441\u0438\u043b\u043e\u0439.","cosmic_weekday_6",null)
B.Ps=new A.an("Tiferet leads today \u2014 seek the beauty that unites opposites around you.","\u0421\u0435\u0433\u043e\u0434\u043d\u044f \u0432\u0435\u0434\u0451\u0442 \u0422\u0438\u0444\u0435\u0440\u0435\u0442 \u2014 \u0438\u0449\u0438 \u043a\u0440\u0430\u0441\u043e\u0442\u0443, \u043e\u0431\u044a\u0435\u0434\u0438\u043d\u044f\u044e\u0449\u0443\u044e \u043f\u0440\u043e\u0442\u0438\u0432\u043e\u043f\u043e\u043b\u043e\u0436\u043d\u043e\u0441\u0442\u0438.","cosmic_weekday_7",null)
B.P8=new A.an("Netzach rules today. Persist in one creative endeavor without looking back.","\u0421\u0435\u0433\u043e\u0434\u043d\u044f \u043f\u0440\u0430\u0432\u0438\u0442 \u041d\u0435\u0446\u0430\u0445. \u0423\u043f\u043e\u0440\u0441\u0442\u0432\u0443\u0439 \u0432 \u043e\u0434\u043d\u043e\u043c \u0442\u0432\u043e\u0440\u0447\u0435\u0441\u043a\u043e\u043c \u0434\u0435\u043b\u0435, \u043d\u0435 \u043e\u0433\u043b\u044f\u0434\u044b\u0432\u0430\u044f\u0441\u044c.","cosmic_weekday_8",null)
